for transfer in contract.transfer_ids:
    if transfer.is_deslocated:
        if transfer.transfer_end_date and transfer.transfer_start_date:
            if transfer.transfer_end_date >= payslip.date_from and transfer.transfer_end_date <= payslip.date_to:
                if transfer.transfer_start_date >= payslip.date_from:
                    days = abs((transfer.transfer_end_date - transfer.transfer_start_date).days) + 1
                    hours += days * contract.resource_calendar_id.hours_per_day
                    total = hours
                else:
                    days = abs((transfer.transfer_end_date.day - payslip.date_from.day).days) + 1
                    hours += days * contract.resource_calendar_id.hours_per_day
                    total = hours
            else:
                if transfer.transfer_start_date >= payslip.date_from:
                    days = abs((payslip.date_to.day - transfer.transfer_start_date.day).days) + 1
                    hours += days * contract.resource_calendar_id.hours_per_day
                    total = hours
                elif transfer.transfer_end_date > payslip.date_to:
                    days = 30
                    hours = days * contract.resource_calendar_id.hours_per_day
                    total = hours
        elif transfer.transfer_end_date:
            if transfer.transfer_start_date >= payslip.date_from:
                days = abs((payslip.date_to.day - transfer.transfer_start_date.day).days) + 1
                hours += days * contract.resource_calendar_id.hours_per_day
                total = hours
            else:
                days = abs((payslip.date_to.day - payslip.date_from.day).days) + 1
                hours += days * contract.resource_calendar_id.hours_per_day
                total = hours
        elif not transfer.transfer_end_date and transfer.transfer_start_date >= payslip.date_from:
            days = abs((payslip.date_to.day - transfer.transfer_start_date.day).days) + 1
            hours += days * contract.resource_calendar_id.hours_per_day
            total = hours
        else:
            days = 30
            hours = days * contract.resource_calendar_id.hours_per_day
            total = hours
