total = 0
work_entries = payslip.env['hr.work.entry'].search([('employee_id', '=', employee.id),('date_start', '>=', payslip.date_from), ('date_start', '<', payslip.date_to)])
for entry in work_entries:
    if entry.work_entry_type_id.code == 'EXTRA_HOURS':
        if (entry.date_start.hour + 1) < 20 and (entry.date_stop.hour + 1) < 20:
            total += ((contract.wage / 208) * 1.5) * entry.duration
        if (entry.date_start.hour + 1) < 20 and ((entry.date_stop.hour + 1) > 20 or entry.date_stop.day > entry.date_start.day):
            minutes = entry.date_start.minute / 60
            before_20_duration = 20 - (entry.date_start.hour + 1 + minutes)
            before_20 = before_20_duration * ((contract.wage / 208) * 1.5)
            total += before_20
result = total

